systemd (Linux)launchd (macOS)Docker <pre><code>[Unit]
Description=SafeAI Proxy
After=network.target

[Service]
ExecStart=/usr/bin/python -m safeai.cli.main serve \
  --mode sidecar --host 127.0.0.1 --port 8910 --config /etc/safeai/safeai.yaml
Restart=on-failure
User=safeai

[Install]
WantedBy=multi-user.target
</code></pre> <pre><code>&lt;?xml version="1.0" encoding="UTF-8"?&gt;
